467 
468           if (IsNSW)
469             I.setHasNoSignedWrap(true);
470 
471           Changed = true;
472           ++NumReassoc;
473           continue;
474         }
475       }
476 
477       // Transform: "A op (B op C)" ==> "(A op B) op C" if "A op B" simplifies.
