2453 /// Fold icmp ({al}shr X, Y), C.
2454 Instruction *InstCombinerImpl::foldICmpShrConstant(ICmpInst &Cmp,
2455                                                    BinaryOperator *Shr,
2456                                                    const APInt &C) {
2457   // An exact shr only shifts out zero bits, so:
2458   // icmp eq/ne (shr X, Y), 0 --> icmp eq/ne X, 0
2459   Value *X = Shr->getOperand(0);
2460   CmpInst::Predicate Pred = Cmp.getPredicate();
2461   if (Cmp.isEquality() && Shr->isExact() && C.isZero())
2462     return new ICmpInst(Pred, X, Cmp.getOperand(1));
2463 
2464   bool IsAShr = Shr->getOpcode() == Instruction::AShr;
2465   const APInt *ShiftValC;
2466   if (match(X, m_APInt(ShiftValC))) {
2467     if (Cmp.isEquality())
2468       return foldICmpShrConstConst(Cmp, Shr->getOperand(1), C, *ShiftValC);
2469 
2470     // (ShiftValC >> Y) >s -1 --> Y != 0 with ShiftValC < 0
2471     // (ShiftValC >> Y) <s  0 --> Y == 0 with ShiftValC < 0
2472     bool TrueIfSigned;
2473     if (!IsAShr && ShiftValC->isNegative() &&
2474         isSignBitCheck(Pred, C, TrueIfSigned))
2475       return new ICmpInst(TrueIfSigned ? CmpInst::ICMP_EQ : CmpInst::ICMP_NE,
2476                           Shr->getOperand(1),
2477                           ConstantInt::getNullValue(X->getType()));
2478 
2479     // If the shifted constant is a power-of-2, test the shift amount directly:
2480     // (ShiftValC >> Y) >u C --> X <u (LZ(C) - LZ(ShiftValC))
2481     // (ShiftValC >> Y) <u C --> X >=u (LZ(C-1) - LZ(ShiftValC))
2482     if (!IsAShr && ShiftValC->isPowerOf2() &&
2483         (Pred == CmpInst::ICMP_UGT || Pred == CmpInst::ICMP_ULT)) {
2484       bool IsUGT = Pred == CmpInst::ICMP_UGT;
2485       assert(ShiftValC->uge(C) && "Expected simplify of compare");
2486       assert((IsUGT || !C.isZero()) && "Expected X u< 0 to simplify");
2487 
2488       unsigned CmpLZ = IsUGT ? C.countl_zero() : (C - 1).countl_zero();
2489       unsigned ShiftLZ = ShiftValC->countl_zero();
2490       Constant *NewC = ConstantInt::get(Shr->getType(), CmpLZ - ShiftLZ);
2491       auto NewPred = IsUGT ? CmpInst::ICMP_ULT : CmpInst::ICMP_UGE;
2492       return new ICmpInst(NewPred, Shr->getOperand(1), NewC);
2493     }
2494   }
2495 
2496   const APInt *ShiftAmtC;
2497   if (!match(Shr->getOperand(1), m_APInt(ShiftAmtC)))
2498     return nullptr;
2499 
2500   // Check that the shift amount is in range. If not, don't perform undefined
2501   // shifts. When the shift is visited it will be simplified.
2502   unsigned TypeBits = C.getBitWidth();
2503   unsigned ShAmtVal = ShiftAmtC->getLimitedValue(TypeBits);
2504   if (ShAmtVal >= TypeBits || ShAmtVal == 0)
2505     return nullptr;
2506 
2507   bool IsExact = Shr->isExact();
2508   Type *ShrTy = Shr->getType();
2509   // TODO: If we could guarantee that InstSimplify would handle all of the
2510   // constant-value-based preconditions in the folds below, then we could assert
2511   // those conditions rather than checking them. This is difficult because of
2512   // undef/poison (PR34838).
2513   if (IsAShr && Shr->hasOneUse()) {
2514     if (IsExact && (Pred == CmpInst::ICMP_SLT || Pred == CmpInst::ICMP_ULT) &&
2515         (C - 1).isPowerOf2() && C.countLeadingZeros() > ShAmtVal) {
2516       // When C - 1 is a power of two and the transform can be legally
2517       // performed, prefer this form so the produced constant is close to a
2518       // power of two.
2519       // icmp slt/ult (ashr exact X, ShAmtC), C
2520       // --> icmp slt/ult X, (C - 1) << ShAmtC) + 1
2521       APInt ShiftedC = (C - 1).shl(ShAmtVal) + 1;
2522       return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2523     }
2524     if (IsExact || Pred == CmpInst::ICMP_SLT || Pred == CmpInst::ICMP_ULT) {
2525       // When ShAmtC can be shifted losslessly:
2526       // icmp PRED (ashr exact X, ShAmtC), C --> icmp PRED X, (C << ShAmtC)
2527       // icmp slt/ult (ashr X, ShAmtC), C --> icmp slt/ult X, (C << ShAmtC)
2528       APInt ShiftedC = C.shl(ShAmtVal);
2529       if (ShiftedC.ashr(ShAmtVal) == C)
2530         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2531     }
2532     if (Pred == CmpInst::ICMP_SGT) {
2533       // icmp sgt (ashr X, ShAmtC), C --> icmp sgt X, ((C + 1) << ShAmtC) - 1
2534       APInt ShiftedC = (C + 1).shl(ShAmtVal) - 1;
2535       if (!C.isMaxSignedValue() && !(C + 1).shl(ShAmtVal).isMinSignedValue() &&
2536           (ShiftedC + 1).ashr(ShAmtVal) == (C + 1))
2537         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2538     }
2539     if (Pred == CmpInst::ICMP_UGT) {
2540       // icmp ugt (ashr X, ShAmtC), C --> icmp ugt X, ((C + 1) << ShAmtC) - 1
2541       // 'C + 1 << ShAmtC' can overflow as a signed number, so the 2nd
2542       // clause accounts for that pattern.
2543       APInt ShiftedC = (C + 1).shl(ShAmtVal) - 1;
2544       if ((ShiftedC + 1).ashr(ShAmtVal) == (C + 1) ||
2545           (C + 1).shl(ShAmtVal).isMinSignedValue())
2546         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2547     }
2548 
2549     // If the compare constant has significant bits above the lowest sign-bit,
2550     // then convert an unsigned cmp to a test of the sign-bit:
2551     // (ashr X, ShiftC) u> C --> X s< 0
2552     // (ashr X, ShiftC) u< C --> X s> -1
2553     if (C.getBitWidth() > 2 && C.getNumSignBits() <= ShAmtVal) {
2554       if (Pred == CmpInst::ICMP_UGT) {
2555         return new ICmpInst(CmpInst::ICMP_SLT, X,
2556                             ConstantInt::getNullValue(ShrTy));
2557       }
2558       if (Pred == CmpInst::ICMP_ULT) {
2559         return new ICmpInst(CmpInst::ICMP_SGT, X,
2560                             ConstantInt::getAllOnesValue(ShrTy));
2561       }
2562     }
2563   } else if (!IsAShr) {
2564     if (Pred == CmpInst::ICMP_ULT || (Pred == CmpInst::ICMP_UGT && IsExact)) {
2565       // icmp ult (lshr X, ShAmtC), C --> icmp ult X, (C << ShAmtC)
2566       // icmp ugt (lshr exact X, ShAmtC), C --> icmp ugt X, (C << ShAmtC)
2567       APInt ShiftedC = C.shl(ShAmtVal);
2568       if (ShiftedC.lshr(ShAmtVal) == C)
2569         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2570     }
2571     if (Pred == CmpInst::ICMP_UGT) {
2572       // icmp ugt (lshr X, ShAmtC), C --> icmp ugt X, ((C + 1) << ShAmtC) - 1
2573       APInt ShiftedC = (C + 1).shl(ShAmtVal) - 1;
2574       if ((ShiftedC + 1).lshr(ShAmtVal) == (C + 1))
2575         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2576     }
2577   }
2578 
2579   if (!Cmp.isEquality())
2580     return nullptr;
2581 
2582   // Handle equality comparisons of shift-by-constant.
2583 
2584   // If the comparison constant changes with the shift, the comparison cannot
2585   // succeed (bits of the comparison constant cannot match the shifted value).
2586   // This should be known by InstSimplify and already be folded to true/false.
2587   assert(((IsAShr && C.shl(ShAmtVal).ashr(ShAmtVal) == C) ||
2588           (!IsAShr && C.shl(ShAmtVal).lshr(ShAmtVal) == C)) &&
2589          "Expected icmp+shr simplify did not occur.");
2590 
2591   // If the bits shifted out are known zero, compare the unshifted value:
2592   //  (X & 4) >> 1 == 2  --> (X & 4) == 4.
2593   if (Shr->isExact())
2594     return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, C << ShAmtVal));
2595 
2596   if (C.isZero()) {
2597     // == 0 is u< 1.
2598     if (Pred == CmpInst::ICMP_EQ)
2599       return new ICmpInst(CmpInst::ICMP_ULT, X,
2600                           ConstantInt::get(ShrTy, (C + 1).shl(ShAmtVal)));
2601     else
2602       return new ICmpInst(CmpInst::ICMP_UGT, X,
2603                           ConstantInt::get(ShrTy, (C + 1).shl(ShAmtVal) - 1));
2604   }
2605 
2606   if (Shr->hasOneUse()) {
2607     // Canonicalize the shift into an 'and':
2608     // icmp eq/ne (shr X, ShAmt), C --> icmp eq/ne (and X, HiMask), (C << ShAmt)
2609     APInt Val(APInt::getHighBitsSet(TypeBits, TypeBits - ShAmtVal));
2610     Constant *Mask = ConstantInt::get(ShrTy, Val);
2611     Value *And = Builder.CreateAnd(X, Mask, Shr->getName() + ".mask");
2612     return new ICmpInst(Pred, And, ConstantInt::get(ShrTy, C << ShAmtVal));
2613   }
2614 
2615   return nullptr;
2616 }
